        <script type="text/javascript" nonce="@Html.ScriptNonce()">
          $('#btnAddAreasTCP').click(function (e) {
            e.preventDefault();
            var v_PartId = $("#txtPartID").val();
            var v_AreaID = $("#ddlAreaIdAreasTCP").val();
            var v_Side = $("#intSideAreasTCP").val();
            var v_IP = $("#intIPAreasTCP").val();
            var v_Port = $("#intPortAreasTCP").val();
            var v_ClientServer = $("#intClientServerAreasTCP").val();
            var v_TcpType = $("#intTcpTypeAreasTCP").val();
            var v_Slave = $("#intSlaveAreasTCP").val();

            var req = { PartID: v_PartId, AreaID: v_AreaID, Side: v_Side, IP: v_IP, Port: v_Port, CLIENTORSERVER: v_ClientServer, TCPTYPE: v_TcpType, Slave: v_Slave };

            ajaxfncAreasTCP(req);
          });

          function updateAreasTCP() {
            var grid = new MvcGrid(document.querySelector('#mvcAreasTCP'));
            grid.requestType = 'post';
            grid.reload();
          };

          function ajaxfncAreasTCP(req) {
            $.ajax({
              type: "POST",
              url: "/Engineering/PartNumber/AddAreasTCP",
              async: false,
              contentType: "application/json; charset=utf-8",
              data: JSON.stringify(req),
              success: function () {
                updateAreasTCP();
              }
            })
          };

          $(document).on('click', '#mvcAreasTCP>table>tbody>tr>td>a.delRow', function (e) {
            e.preventDefault();
            var target = $(this).attr("href");

            $.ajax({
              type: "POST",
              url: target,
              async: false,
              contentType: "application/json; charset=utf-8",
              success: function () {
                updateAreasTCP();
              }
            })
          });
        </script>
